UPDATE user_songs
SET rating = #{rating}
WHERE user_id = #{userId}
  AND song_id = #{songId}

UPDATE user_songs
SET play_count = play_count + 1,
    last_played_at = NOW()
WHERE user_id = #{userId}
  AND song_id = #{songId}

UPDATE user_songs
SET is_saved = 0
WHERE user_id = #{userId}
  AND song_id = #{songId}
